*/
void ZopfliLengthsToSymbols(const unsigned *lengths, size_t n, unsigned maxbits,
                            unsigned *symbols)
{
    size_t *bl_count = (size_t *)malloc(sizeof(size_t) * (maxbits + 1));
    size_t *next_code = (size_t *)malloc(sizeof(size_t) * (maxbits + 1));
    unsigned bits, i;
    unsigned code;

    for (i = 0; i < n; i++)
    {
        symbols[i] = 0;
    }

