    number of codes of length N, N >= 1. */
    for (bits = 0; bits <= maxbits; bits++)
    {
        bl_count[bits] = 0;
    }
    for (i = 0; i < n; i++)
    {
        assert(lengths[i] <= maxbits);
        bl_count[lengths[i]]++;
    }
