    code = 0;
    bl_count[0] = 0;
    for (bits = 1; bits <= maxbits; bits++)
    {
        code = (code + bl_count[bits - 1]) << 1;
        next_code[bits] = code;
    }
    /* 3) Assign numerical values to all codes, using consecutive values for all
    codes of the same length with the base values determined at step 2. */
    for (i = 0; i < n; i++)
    {
